diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
index 76234ccfdcff..14b51a5a6e2b 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
@@ -1862,6 +1862,7 @@ static Instruction *foldSubOfMinMax(BinaryOperator &I,
   return nullptr;
 }

+
 Instruction *InstCombinerImpl::visitSub(BinaryOperator &I) {
   if (Value *V = simplifySubInst(I.getOperand(0), I.getOperand(1),
                                  I.hasNoSignedWrap(), I.hasNoUnsignedWrap(),
@@ -2031,6 +2032,46 @@ Instruction *InstCombinerImpl::visitSub(BinaryOperator &I) {
       return BinaryOperator::CreateAdd(X, ConstantExpr::getSub(C, C2));
   }

+  // Optimize: sub C3, (and (sub nuw C1, X), C2)
+  // where C2 = -K for some power of 2 K, C3 = C1 & C2, and C1 mod K = K - 1.
+  // This simplifies to: and X, (C2 & ((1 << num_bits) - 1))
+  // where num_bits is the minimum number of bits to represent C1.
+  {
+    const APInt *C3;
+    Value *AndOp0, *AndOp1;
+    if (match(Op0, m_APInt(C3)) &&
+        match(Op1, m_OneUse(m_And(m_Value(AndOp0), m_Value(AndOp1))))) {
+      Value *InnerSub = nullptr;
+      const APInt *C2 = nullptr;
+
+      if (match(AndOp0, m_APInt(C2))) {
+        InnerSub = AndOp1;
+      } else if (match(AndOp1, m_APInt(C2))) {
+        InnerSub = AndOp0;
+      }
+
+      if (InnerSub && C2 && C2->isNegative() && (-*C2).isPowerOf2()) {
+        Value *X;
+        const APInt *C1;
+        if (match(InnerSub, m_OneUse(m_Sub(m_APInt(C1), m_Value(X))))) {
+          auto *BO = cast<BinaryOperator>(InnerSub);
+          if (BO->hasNoUnsignedWrap() && *C3 == (*C1 & *C2)) {
+            APInt LowBitsC1 = *C1 & ~(*C2);
+            if (LowBitsC1 == ~(*C2)) {
+              unsigned NumBits = C1->getActiveBits();
+              APInt RefinedMask = *C2;
+              if (NumBits < C1->getBitWidth()) {
+                RefinedMask &= APInt::getLowBitsSet(C1->getBitWidth(), NumBits);
+              }
+              return BinaryOperator::CreateAnd(
+                  X, ConstantInt::get(I.getType(), RefinedMask));
+            }
+          }
+        }
+      }
+    }
+  }
+
   const APInt *Op0C;
   if (match(Op0, m_APInt(Op0C)) && Op0C->isMask()) {
     // Turn this into a xor if LHS is 2^n-1 and the remaining bits are known
@@ -2301,6 +2342,7 @@ Instruction *InstCombinerImpl::visitSub(BinaryOperator &I) {
   return TryToNarrowDeduceFlags();
 }

+
 /// This eliminates floating-point negation in either 'fneg(X)' or
 /// 'fsub(-0.0, X)' form by combining into a constant operand.
 static Instruction *foldFNegIntoConstant(Instruction &I, const DataLayout &DL) {

